#include <stdio.h>
int main() {
    int T, n;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &n);
        printf("%d\n", n / 2 + (n % 2));
        for (int i = 1; i <= n / 2; i++) {
            printf("2\n%d %d %d\n%d %d %d\n", i, i, n - i + 1, n - i + 1, i, n - i + 1);
        }
        if (n % 2) {
            printf("1\n%d %d %d\n", n / 2 + 1, n / 2 + 1, n);
        }
    }
    return 0;
}

