            cout << "1" << endl;
            cout << n / 2 + 1 << " " << n / 2 + 1 << " " << n << endl;
        }
    }
    return 0;
}

code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            System.out.println(n / 2 + (n % 2));
            for (int i = 1; i <= n / 2; i++) {
                System.out.println("2");
                System.out.println(i + " " + i + " " + (n - i + 1));
                System.out.println((n - i + 1) + " " + i + " " + (n - i + 1));
            }
            if (n % 2 != 0) {
                System.out.println("1");
                System.out.println((n / 2 + 1) + " " + (n / 2 + 1) + " " + n);
            }
        }
    }
}

